// 【5】餐厅点餐英语
// ══════════════════════════════════════════════════════════════
window.QB_EN_RESTAURANT=[
  {c:'出国',q:'进入餐厅，服务员问"Do you have a reservation?"，你没有预订，应该说？',o:['No, we don\'t. Is there a table for two?','Yes, under the name Zhang.','We want to sit outside.','Can we see the menu?'],a:0,e:'没有预订时说"No, we don\'t."然后询问有没有位置。two=两人，按人数替换。'},
  {c:'出国',q:'服务员问"How would you like your steak?"，这是问？',o:['牛排要几分熟','牛排要加什么配料','牛排要用什么酱汁','想要多大份的牛排'],a:0,e:'这是在问牛排的熟度。选项：rare（一分熟）/medium rare（三分熟）/medium（五分熟）/well done（全熟）'},
  {c:'出国',q:'你对某种食物过敏，应该提前告诉服务员：',o:['I\'m allergic to nuts / seafood. Does this dish contain any?','I\'d like a vegetarian option.','Can I get this without onions?','This tastes too spicy.'],a:0,e:'allergic to=对……过敏，contain=含有。食物过敏是严重问题，一定要提前说清楚！'},
  {c:'出国',q:'"The bill, please."这句话是什么意思？',o:['麻烦结账','请再给我一份','请推荐一道菜','这道菜太咸了'],a:0,e:'"The bill, please."=请结账（英式）。美式常说"Check, please."或"Can we get the check?"'},
  {c:'出国',q:'你的食物送错了，应该说？',o:['Excuse me, I think there\'s a mistake with my order.','This is not what I ordered.','I didn\'t order this.','All three are correct.'],a:0,e:'前三个都正确。最礼貌的是"I think there\'s a mistake"，不直接说对方的错，给双方都留面子。'},
  {c:'出国',q:'你想要一杯白开水，应该说？',o:['Could I have a glass of still water, please?','Can I have sparkling water?','I\'d like iced water.','A cup of tap water, please.'],a:0,e:'still water=无气泡水（白开水），sparkling water=有气泡水，tap water=自来水。注意区分！'},
  {c:'出国',q:'"This dish is recommended."意思是？',o:['这道菜是招牌推荐','这道菜已经售完','这道菜比较辣','这道菜需要额外收费'],a:0,e:'recommended=推荐的。餐厅菜单上常见"Chef\'s Recommendation（厨师推荐）"或"House Special（招牌菜）"。'},
  {c:'出国',q:'你想外带食物，应该说？',o:['Can I get this to go? / For takeaway, please.','I\'ll eat here.','Can I have a doggy bag?','Is there a drive-through?'],a:0,e:'"to go"（美式）/ "takeaway"（英式）=外带。"doggy bag"=打包袋（把剩菜打包带走）。'},
  {c:'出国',q:'账单上显示"service charge included"，意思是？',o:['已包含服务费，不需要额外给小费','服务费额外计算','包含税费','小费自愿给'],a:0,e:'service charge included=已包含服务费。如果没有注明，在欧美国家通常需要给小费（10-20%）。'},
  {c:'出国',q:'你想问服务员有没有素食菜单，应该说？',o:['Do you have a vegetarian menu / any vegetarian options?','I\'m vegan.','I don\'t eat pork.','Is this dish gluten-free?'],a:0,e:'vegetarian=素食者（不吃肉），vegan=纯素食者（不吃任何动物产品）。gluten-free=无麸质。'},
];

